<div class="grid gap-4 md:grid-cols-2"><x-form.checkbox name="ticket_email_notifications_enabled" label="ارسال ایمیل تیکت فعال باشد" :checked="$ticketEmailNotificationsEnabled" /><x-form.checkbox name="ticket_sms_notifications_enabled" label="ارسال پیامک تیکت فعال باشد" :checked="$ticketSmsNotificationsEnabled" /></div>
<div class="rounded-xl border border-amber-200 bg-amber-50 p-4"><h2 class="text-sm font-black text-amber-900">قالب‌های کاوه‌نگار</h2><p class="mt-1 text-xs leading-6 text-amber-800">token = شماره تیکت، token2 = نام مشتری/اپراتور، token3 = دسته‌بندی یا وضعیت.</p><div class="mt-4 grid gap-4 md:grid-cols-2"><x-form.input name="ticket_kavenegar_customer_created_template" label="Customer: ticket created" :value="$ticketKavenegarCustomerCreatedTemplate" dir-ltr /><x-form.input name="ticket_kavenegar_admin_new_template" label="Admin: new ticket" :value="$ticketKavenegarAdminNewTemplate" dir-ltr /><x-form.input name="ticket_kavenegar_customer_reply_template" label="Customer: admin reply" :value="$ticketKavenegarCustomerReplyTemplate" dir-ltr /><x-form.input name="ticket_kavenegar_admin_reply_template" label="Admin: customer reply" :value="$ticketKavenegarAdminReplyTemplate" dir-ltr /><x-form.input name="ticket_kavenegar_assignment_template" label="Assignment notice" :value="$ticketKavenegarAssignmentTemplate" dir-ltr /></div></div>
